// Domain types

type Role string

const (
	RoleAdmin    Role = "admin"
	RoleManager  Role = "manager"
	RoleCustomer Role = "customer"
)

type User struct {
	ID       string
	TenantID string
	Role     Role
}

type Order struct {
	ID         string  `json:"id"`
	TenantID   string  `json:"tenant_id"`
	UserID     string  `json:"user_id"`
	Product    string  `json:"product"`
	Quantity   int     `json:"quantity"`
	Status     string  `json:"status"`
	TotalPrice float64 `json:"total_price"`
	Notes      string  `json:"notes"`
}

// Context key for authenticated user
type contextKey string

const userContextKey contextKey = "authenticated_user"

// GetUserFromContext retrieves the authenticated user set by auth middleware
func GetUserFromContext(ctx context.Context) (*User, error) {
	user, ok := ctx.Value(userContextKey).(*User)
	if !ok || user == nil {
		return nil, errors.New("user not found in context")
	}
	return user, nil
}

// Authorization errors
var (
	ErrUnauthorized    = errors.New("unauthorized")
	ErrForbidden       = errors.New("forbidden: insufficient permissions")
	ErrTenantMismatch  = errors.New("forbidden: tenant mismatch")
	ErrResourceDenied  = errors.New("forbidden: access to resource denied")
)

// AuthorizationService handles all authorization checks
type AuthorizationService struct{}

// CanAccessOrder checks if the user is authorized to view the given order.
// Enforces tenant isolation, role-based access, and resource ownership.
func (a *AuthorizationService) CanAccessOrder(user *User, order *Order) error {
	// 1. Tenant isolation: user must belong to the same tenant as the order
	if user.TenantID != order.TenantID {
		return ErrTenantMismatch
	}

	// 2. Role-based access control
	switch user.Role {
	case RoleAdmin:
		// Admins can access any order within their tenant
		return nil
	case RoleManager:
		// Managers can access any order within their tenant
		return nil
	case RoleCustomer:
		// Customers can only access their own orders
		if user.ID != order.UserID {
			return ErrResourceDenied
		}
		return nil
	default:
		return ErrForbidden
	}
}

// FilterOrderFields returns a sanitized view of the order based on the user's role.
// Certain fields are only visible to certain roles.
func (a *AuthorizationService) FilterOrderFields(user *User, order *Order) map[string]interface{} {
	// Base fields visible to all authorized users
	result := map[string]interface{}{
		"id":       order.ID,
		"product":  order.Product,
		"quantity": order.Quantity,
		"status":   order.Status,
	}

	// Managers and admins can see additional fields
	if user.Role == RoleAdmin || user.Role == RoleManager {
		result["tenant_id"] = order.TenantID
		result["user_id"] = order.UserID
		result["total_price"] = order.TotalPrice
		result["notes"] = order.Notes
	}

	// Customers can see their own total price but not internal notes
	if user.Role == RoleCustomer {
		result["total_price"] = order.TotalPrice
	}

	return result
}

// CanUpdateOrderField checks if a user with the given role can update a specific field
func (a *AuthorizationService) CanUpdateOrderField(user *User, fieldName string) error {
	// Tenant isolation is assumed to be checked before calling this

	allowedFields := map[Role]map[string]bool{
		RoleAdmin: {
			"product": true, "quantity": true, "status": true,
			"total_price": true, "notes": true, "user_id": true,
		},
		RoleManager: {
			"status": true, "notes": true, "total_price": true,
		},
		RoleCustomer: {
			"quantity": true,
			// Customers can only update quantity (e.g., before order is confirmed)
		},
	}

	fields, ok := allowedFields[user.Role]
	if !ok {
		return ErrForbidden
	}

	if !fields[fieldName] {
		return fmt.Errorf("forbidden: role %s cannot update field %s", user.Role, fieldName)
	}

	return nil
}

// OrderRepository handles database access for orders
type OrderRepository struct {
	DB *sql.DB
}

// GetByID fetches an order by its ID from the database.
// Note: We intentionally do NOT filter by tenant here — authorization is handled
// separately so we can return proper error codes (403 vs 404).
func (r *OrderRepository) GetByID(ctx context.Context, orderID string) (*Order, error) {
	query := `SELECT id, tenant_id, user_id, product, quantity, status, total_price, notes 
	          FROM orders WHERE id = $1`

	order := &Order{}
	err := r.DB.QueryRowContext(ctx, query, orderID).Scan(
		&order.ID,
		&order.TenantID,
		&order.UserID,
		&order.Product,
		&order.Quantity,
		&order.Status,
		&order.TotalPrice,
		&order.Notes,
	)
	if err != nil {
		if errors.Is(err, sql.ErrNoRows) {
			return nil, nil
		}
		return nil, fmt.Errorf("database error fetching order: %w", err)
	}

	return order, nil
}

// GetOrderHandler returns an HTTP handler for GET /orders/{orderID}
func GetOrderHandler(repo *OrderRepository, authz *AuthorizationService) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		// Only allow GET
		if r.Method != http.MethodGet {
			http.Error(w, "method not allowed", http.StatusMethodNotAllowed)
			return
		}

		// Extract authenticated user from context (set by auth middleware)
		user, err := GetUserFromContext(r.Context())
		if err != nil {
			http.Error(w, "unauthorized", http.StatusUnauthorized)
			return
		}

		// Extract order ID from URL path: /orders/{orderID}
		orderID := extractOrderID(r.URL.Path)
		if orderID == "" {
			http.Error(w, "bad request: missing order ID", http.StatusBadRequest)
			return
		}

		// Validate order ID format to prevent injection
		if !isValidOrderID(orderID) {
			http.Error(w, "bad request: invalid order ID format", http.StatusBadRequest)
			return
		}

		// Fetch order from database
		order, err := repo.GetByID(r.Context(), orderID)
		if err != nil {
			// Log the actual error server-side; return generic message to client
			fmt.Printf("error fetching order %s: %v\n", orderID, err)
			http.Error(w, "internal server error", http.StatusInternalServerError)
			return
		}

		if order == nil {
			// Return 404 — but be careful: if the order exists in another tenant,
			// we still return 404 to avoid leaking information about other tenants.
			http.Error(w, "order not found", http.StatusNotFound)
			return
		}

		// --- Server-side authorization checks ---

		// 1. Tenant isolation check
		// 2. Role-based access check
		// 3. Resource ownership check (for customers)
		if err := authz.CanAccessOrder(user, order); err != nil {
			// For tenant mismatch, return 404 to avoid leaking info
			if errors.Is(err, ErrTenantMismatch) {
				http.Error(w, "order not found", http.StatusNotFound)
				return
			}
			http.Error(w, "forbidden", http.StatusForbidden)
			return
		}

		// 4. Field-level filtering based on role
		filteredOrder := authz.FilterOrderFields(user, order)

		// Return the filtered response
		w.Header().Set("Content-Type", "application/json")
		w.WriteHeader(http.StatusOK)
		if err := json.NewEncoder(w).Encode(filteredOrder); err != nil {
			fmt.Printf("error encoding response: %v\n", err)
		}
	}
}

// extractOrderID extracts the order ID from a URL path like /orders/{orderID}
func extractOrderID(path string) string {
	// Trim trailing slash
	path = strings.TrimSuffix(path, "/")
	parts := strings.Split(path, "/")

	// Expected: ["", "orders", "{orderID}"]
	if len(parts) >= 3 && parts[len(parts)-2] == "orders" {
		return parts[len(parts)-1]
	}
	return ""
}

// isValidOrderID validates the order ID format to prevent injection attacks
func isValidOrderID(id string) bool {
	if len(id) == 0 || len(id) > 128 {
		return false
	}
	for _, c := range id {
		if !((c >= 'a' && c <= 'z') || (c >= 'A' && c <= 'Z') || (c >= '0' && c <= '9') || c == '-' || c == '_') {
			return false
		}
	}
	return true
}

